def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[4] # zero-indexed
    titlebox = None
    targetbox = None
    for shp in slide.shapes:
        if shp.has_text_frame:
            text = shp.text_frame.text.strip()
            if text == "Roll Movement Demonstration":
                targetbox = shp
            if text == slide.shapes.title.text if slide.shapes.title else None:
                titlebox = shp
    if not targetbox:
        return "'Roll Movement Demonstration' text box not found on slide 5.", 0.0
    if not titlebox:
        return "Main title not found on slide 5.", 0.5 # Can't judge position perfectly
    # Check y-coordinate (pptx uses .top in EMUs)
    try:
        if targetbox.top > titlebox.top + titlebox.height:
            return "Text box is visually below the title.", 1.0
        else:
            return "Text box is NOT below the main title.", 0.0
    except Exception as e:
        return f"Exception in position check: {e}", 0.5

def compute_score() -> tuple[str, float]:
    # Look for modifications outside slide 5 in ppt_diff
    changed_or_added_slides = set()
    for (sl1, sl2) in ppt_diff.modified_slides:
        if sl2.slide_number != 5:
            changed_or_added_slides.add(sl2.slide_number)
    for sl in ppt_diff.added_slides:
        if sl.slide_number != 5:
            changed_or_added_slides.add(sl.slide_number)
    for sl in ppt_diff.removed_slides:
        changed_or_added_slides.add(sl.slide_number)
    if changed_or_added_slides:
        return f"Slides changed other than slide 5: {list(changed_or_added_slides)}", 0.0
    return "No modifications detected outside slide 5.", 1.0
